import React, { useState } from "react";
import {
    Button,
    Box,
    Typography,
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Link,
    IconButton,
} from "@mui/material";
import * as XLSX from "xlsx";
import TuneIcon from '@mui/icons-material/Tune';

const ExcelUploaderStorage = ({ open, handleOpen, handleClose }) => {
    const [sheets, setSheets] = useState(null);
    const [dragOver, setDragOver] = useState(false);

    const handleFileUpload = (file) => {
        if (!file) return;

        // Limpia la clave 'excelData' de sessionStorage
        sessionStorage.removeItem("excelData");

        const reader = new FileReader();
        reader.onload = (e) => {
            const data = new Uint8Array(e.target.result);
            const workbook = XLSX.read(data, { type: "array" });
            const sheetsData = {};

            // Procesar cada hoja y convertirla en JSON
            workbook.SheetNames.forEach((sheetName) => {
                const sheet = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], {
                    header: 1, // Mantiene la primera fila como encabezados
                });

                // Filtrar filas vacías
                const filteredSheet = sheet.filter((row) =>
                    row.some((cell) => cell !== null && cell !== undefined && cell !== "")
                );

                sheetsData[sheetName] = filteredSheet;
            });

            // Guardar los datos procesados en el estado y en sessionStorage
            setSheets(sheetsData);
            sessionStorage.setItem("excelData", JSON.stringify(sheetsData));
        };

        reader.readAsArrayBuffer(file);
    };

    const handleInputChange = (event) => {
        const file = event.target.files[0];
        handleFileUpload(file);
    };

    const handleDragOver = (event) => {
        event.preventDefault();
        setDragOver(true);
    };

    const handleDragLeave = () => {
        setDragOver(false);
    };

    const handleDrop = (event) => {
        event.preventDefault();
        setDragOver(false);
        const file = event.dataTransfer.files[0];
        handleFileUpload(file);
    };

    return (
        <Box sx={{ p: 2 }}>


            <Dialog open={open} onClose={handleClose} fullWidth maxWidth="sm">
                <DialogTitle>Subir archivo Excel de parámetros</DialogTitle>
                <DialogContent>
                    <Box
                        sx={{
                            mt: 2,
                            p: 2,
                            border: "2px dashed",
                            borderColor: dragOver ? "primary.main" : "grey.400",
                            borderRadius: 2,
                            textAlign: "center",
                            backgroundColor: dragOver ? "grey.100" : "transparent",
                        }}
                        onDragOver={handleDragOver}
                        onDragLeave={handleDragLeave}
                        onDrop={handleDrop}
                    >
                        <Typography variant="body1" gutterBottom>
                            Arrastra y suelta tu archivo aquí o selecciona uno manualmente
                        </Typography>
                        <Button variant="contained" component="label">
                            Seleccionar Archivo
                            <input
                                type="file"
                                hidden
                                accept=".xlsx, .xls"
                                onChange={handleInputChange}
                            />
                        </Button>
                    </Box>
                    <Box sx={{ mt: 2 }}>
                        <Typography variant="body2">
                            ¿Necesitas una plantilla? Descárgala haciendo clic
                            <Link href="/plantillasParametros/caes.xlsx" download sx={{ ml: 1 }}>
                                aquí
                            </Link>
                            .
                        </Typography>
                    </Box>
                    {sheets && (
                        <Box sx={{ mt: 2 }}>
                            <Typography variant="subtitle1">Hojas procesadas:</Typography>
                            <ul>
                                {Object.keys(sheets).map((sheetName) => (
                                    <li key={sheetName}>{sheetName}</li>
                                ))}
                            </ul>
                        </Box>
                    )}
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleClose} color="primary">
                        Cerrar
                    </Button>
                </DialogActions>
            </Dialog>
        </Box>
    );
};

export default ExcelUploaderStorage;
